import React, { useCallback, useMemo, useRef, useState } from 'react';
import {
  Button,
  Input,
  SearchTextInput,
  Select,
  Modal,
  Checkbox,
  SearchInput,
  dispatchAppToast,
  LeaveConfirmModal,
  useDirtyTracking,
  useLeaveConfirm,
  useViewMobileLayout,
} from '@linm-soft/common-components';
import { useAppDispatch } from '../../../store/hooks';
import { masterService } from '../../../services/master/masterService';
import type { AccountChartMetaDto, AccountDto } from '../../../services/master/models';
import { createAccountSearchConfig, clearAccountSearchCache, formatAccountDisplay } from '../../../components/search';
import { normalizeCode, normalizeSearchText } from '../../../utils/codeField';
import { getSharedCatalogEditBlockedMessage, catalogRowEditHintDismissStorageKey } from '../../../utils/sharedCatalogEditBlockedMessage';
import {
  CATALOG_LIST_ROW_MENU_HINT_DESKTOP,
  CATALOG_LIST_ROW_MENU_HINT_TOUCH,
  catalogListRowMenuHintDismissStorageKey,
} from '../../../utils/catalogListRowMenuHint';
import { isSharedCatalogReadOnly } from '../../../hooks/useSharedCatalog';
import { useCatalogListPermissions } from '../../../hooks/useCatalogListPermissions';
import { scrollToFirstFieldError } from '../../../utils/catalogFormValidation';
import { ListSearchRefreshButtons } from '../../../components/list/ListSearchRefreshButtons';
import { useCatalogListSelection } from '../../../hooks/useCatalogListSelection';
import {
  CatalogFormFooter,
  CatalogListShell,
  useCatalogListPaging,
  useCatalogTableBusy,
  CatalogCompanyTh,
  CatalogCompanyTd,
  SharedCatalogFormActions,
  useSharedCatalog,
  CatalogListGrid,
  CatalogListMasterToolbarSection,
  CatalogListMasterListFooter,
  CatalogFormHistorySlot,
  CatalogFormCodeReplaceSlot,
  CatalogCodeReplaceProvider,
  CatalogListCodeCell,
  CatalogPageHeader,
  CatalogListHeaderFilters,
  CatalogUiSchemaEditorModal,
  useCatalogUiSchema,
  CatalogRowActionMenu,
  type CatalogRowMenuAction,
  type CatalogListToolbarBridge,
} from '../../../components/catalog';
import type { CatalogBatchDeleteMode } from '../../../components/catalog';
import type { SharedCatalogProposalSubmitChange } from '../../../components/catalog/SharedCatalogProposalModal';
import { buildSharedCatalogChangePayloadJson } from '../../../utils/sharedCatalogProposalPayload';
import styles from '../../../styles/erpPage.module.css';
import { selectPlaceholderClass } from '../../../utils/selectField';

const TEST_ID = 'dm-tai-khoan';
const CATALOG_KIND = 'accounts';

type FormErrors = Partial<Record<'code' | 'name', string>>;
type AccountGridRow = AccountDto & { id: string };

const TaiKhoanPage: React.FC = () => {
  const dispatch = useAppDispatch();
  const viewMobile = useViewMobileLayout();
  const { canWrite } = useCatalogListPermissions(CATALOG_KIND);
  const toolbarBridgeRef = useRef<CatalogListToolbarBridge | null>(null);
  const [rowMenu, setRowMenu] = useState<{ x: number; y: number; row: AccountGridRow } | null>(null);
  const { onDirtyChange, guardedNavigate, leaveConfirmModalProps } = useLeaveConfirm({
    message: 'Có thay đổi chưa được lưu. Đóng form sẽ mất dữ liệu đã nhập.',
  });
  const { markDirty, markClean } = useDirtyTracking(onDirtyChange);
  const [searchDraft, setSearchDraft] = useState('');
  const [search, setSearch] = useState('');
  const [items, setItems] = useState<AccountDto[]>([]);
  const sessionCompanyName = useMemo(() => items[0]?.companyName, [items]);
  const [totalCount, setTotalCount] = useState(0);
  const [loading, setLoading] = useState(false);
  const [modalOpen, setModalOpen] = useState(false);
  const [editing, setEditing] = useState<AccountGridRow | null>(null);
  const parentAccountSearchConfig = useMemo(
    () => createAccountSearchConfig({ mode: 'all' }),
    [],
  );
  const [form, setForm] = useState<Partial<AccountDto>>({ isActive: true, isDetail: false });
  const [parentAccountName, setParentAccountName] = useState('');
  const [errors, setErrors] = useState<FormErrors>({});
  const [saving, setSaving] = useState(false);
  const [reloadKey, setReloadKey] = useState(0);
  const [chartMeta, setChartMeta] = useState<AccountChartMetaDto | null>(null);
  const [scopeFilter, setScopeFilter] = useState('');
  const [accountingStandardFilter, setAccountingStandardFilter] = useState('');
  const [scopeFilterOption, setScopeFilterOption] = useState('');
  const [formViewOnly, setFormViewOnly] = useState(false);
  const [schemaEditorOpen, setSchemaEditorOpen] = useState(false);
  const { reload: reloadSchema } = useCatalogUiSchema(CATALOG_KIND);
  const scopeFilterOptions = useMemo<{ value: string; label: string }[]>(
    () => {
      const initOptions = chartMeta?.filterOptions ?? [];
      if (initOptions.length === 0) {
        return [
          { value: '', label: 'Tất cả' },
          { value: 'shared', label: 'Danh mục dùng chung' },
          { value: 'company', label: 'Danh mục riêng theo đơn vị' },
        ];
      }
      return initOptions.map(o => ({ value: o.value, label: o.label }));
    },
    [chartMeta?.filterOptions],
  );

  const handleScopeFilterChange = (value: string) => {
    setScopeFilterOption(value);
    const options = chartMeta?.filterOptions ?? [];
    const selected = options.find(o => o.value === value);
    const selectedScope = selected?.scope === 'Shared' ? 'System' : (selected?.scope ?? '');
    setScopeFilter(selectedScope);
    setAccountingStandardFilter(selected?.accountingStandard ?? '');
    resetPage();
    selection.clearSelection();
  };


  const { page, setPage, pageSize, setPageSize, resetPage } = useCatalogListPaging();
  const { showTableLoading, pulseSearch } = useCatalogTableBusy(loading);
  const tableConfig = useMemo(() => {
    const masterGrid = chartMeta?.tableConfig?.masterGrid;
    if (!masterGrid) return undefined;
    return {
      stickyHeader: masterGrid.stickyHeader ?? true,
      heightMode: masterGrid.heightMode ?? 'auto',
      height: masterGrid.height ?? null,
      resizable: masterGrid.resizableColumns ?? true,
    } as const;
  }, [chartMeta?.tableConfig?.masterGrid]);

  const gridRows = useMemo<AccountGridRow[]>(
    () => items.map(r => ({ ...r, id: r.code })),
    [items],
  );

  const selection = useCatalogListSelection({
    rows: gridRows,
    totalCount,
    page,
    pageSize,
    getRowId: r => r.id,
    isRowSelectable: r => !r.isReadOnly,
  });
  const clearSelection = selection.clearSelection;

  const refresh = () => {
    selection.clearSelection();
    setReloadKey(k => k + 1);
    masterService.getAccountChartMeta()
      .then(setChartMeta)
      .catch(() => { /* optional meta */ });
  };
  const shared = useSharedCatalog(CATALOG_KIND, refresh);

  const applySearch = useCallback(() => {
    pulseSearch(() => {
      const next = normalizeSearchText(searchDraft);
      setSearch(next);
      resetPage();
      clearSelection();
    });
  }, [clearSelection, pulseSearch, resetPage, searchDraft]);

  const handleSearch = useCallback(() => {
    applySearch();
  }, [applySearch]);

  React.useEffect(() => {
    const timer = window.setTimeout(() => {
      applySearch();
    }, 300);
    return () => window.clearTimeout(timer);
  }, [searchDraft, applySearch]);

  React.useEffect(() => {
    let cancelled = false;
    const t = setTimeout(() => {
      masterService.getAccountChartMeta()
        .then(meta => { if (!cancelled) setChartMeta(meta); })
        .catch(() => { /* optional meta */ });
    }, 0);
    return () => { cancelled = true; clearTimeout(t); };
  }, []);

  React.useEffect(() => {
    let cancelled = false;
    setLoading(true);
    const t = setTimeout(() => {
      masterService.getAccounts({
        search: search.trim() || undefined,
        page,
        pageSize,
        scope: scopeFilter ? (scopeFilter as 'System' | 'Company') : undefined,
        accountingStandard: accountingStandardFilter || undefined,
      })
        .then(data => {
          if (!cancelled) {
            setItems(data.items);
            setTotalCount(data.totalCount);
          }
        })
        .catch(err => {
          if (!cancelled) dispatchAppToast(dispatch, { message: err?.message ?? 'Lỗi tải tài khoản', type: 'error' });
        })
        .finally(() => { if (!cancelled) setLoading(false); });
    }, 0);
    return () => { cancelled = true; clearTimeout(t); };
  }, [search, page, pageSize, reloadKey, scopeFilter, accountingStandardFilter, dispatch]);

  React.useEffect(() => {
    if (!modalOpen || !form.parentCode?.trim()) {
      if (!form.parentCode) setParentAccountName('');
      return;
    }
    let cancelled = false;
    const t = setTimeout(() => {
      masterService.getAccounts({ search: form.parentCode, page: 1, pageSize: 20 }).then(res => {
        if (!cancelled) {
          const a = res.items.find(x => x.code === form.parentCode);
          setParentAccountName(a?.name ?? '');
        }
      });
    }, 0);
    return () => {
      cancelled = true;
      clearTimeout(t);
    };
  }, [modalOpen, form.parentCode]);

  const clearFieldError = (key: keyof FormErrors) => {
    setErrors(prev => {
      if (!prev[key]) return prev;
      const next = { ...prev };
      delete next[key];
      return next;
    });
  };

  const validate = (): FormErrors => {
    const next: FormErrors = {};
    if (!editing && !form.code?.trim()) next.code = 'Nhập mã tài khoản';
    if (!form.name?.trim()) next.name = 'Nhập tên tài khoản';
    return next;
  };

  const closeFormModal = () => {
    guardedNavigate(() => {
      markClean();
      setModalOpen(false);
    });
  };

  const openAdd = () => {
    setFormViewOnly(false);
    setEditing(null);
    setForm({ isActive: true, isDetail: false });
    setParentAccountName('');
    setErrors({});
    markClean();
    setModalOpen(true);
  };

  const openView = useCallback((row: AccountGridRow) => {
    setFormViewOnly(true);
    setEditing(row);
    setForm({ ...row });
    setParentAccountName('');
    setErrors({});
    markClean();
    setModalOpen(true);
  }, [markClean]);

  const openEdit = useCallback((row: AccountGridRow) => {
    if (!canWrite || isSharedCatalogReadOnly(row)) {
      openView(row);
      return;
    }
    setFormViewOnly(false);
    setEditing(row);
    setForm({ ...row });
    setParentAccountName('');
    setErrors({});
    markClean();
    setModalOpen(true);
  }, [canWrite, markClean, openView]);

  const handleSave = async () => {
    const nextErrors = validate();
    if (Object.keys(nextErrors).length > 0) {
      setErrors(nextErrors);
      scrollToFirstFieldError(TEST_ID);
      return;
    }
    setSaving(true);
    try {
      if (editing) {
        await masterService.updateAccount(editing.code, {
          name: form.name,
          parentCode: form.parentCode || undefined,
          isDetail: form.isDetail,
          isActive: form.isActive,
          note: form.note,
        });
      } else {
        await masterService.createAccount({
          ...form,
          scope: 'Company',
        });
      }
      markClean();
      dispatchAppToast(dispatch, {
        message: editing ? 'Cập nhật tài khoản thành công' : 'Tạo tài khoản thành công',
        type: 'success',
      });
      setModalOpen(false);
      clearAccountSearchCache();
      refresh();
    } catch (err: unknown) {
      dispatchAppToast(dispatch, { message: err instanceof Error ? err.message : 'Lưu thất bại', type: 'error' });
    } finally {
      setSaving(false);
    }
  };

  const handleSubmitProposalChange = async (
    entityKey: string,
    submit: SharedCatalogProposalSubmitChange,
  ) => {
    await masterService.createSharedCatalogChangeRequest({
      catalogKind: CATALOG_KIND,
      action: submit.action,
      entityKey,
      payloadJson: buildSharedCatalogChangePayloadJson(submit),
    });
    const actionLabel = submit.action === 'Create' ? 'đưa vào dùng chung' : submit.action === 'Update' ? 'sửa' : 'xóa';
    dispatchAppToast(dispatch, { message: `Đã gửi đề xuất ${actionLabel} — chờ duyệt`, type: 'success' });
  };

  const resolveDeleteCodes = (): string[] => {
    if (selection.selectionMode === 'all') {
      return items.filter(r => !r.isReadOnly).map(r => r.code);
    }
    return [...selection.selectedIds]
      .map(id => gridRows.find(r => r.id === id))
      .filter((r): r is AccountGridRow => !!r && !r.isReadOnly)
      .map(r => r.code);
  };

  const handleBatchDelete = async (mode: CatalogBatchDeleteMode) => {
    const codes = resolveDeleteCodes();
    if (codes.length === 0) throw new Error('Không có bản ghi hợp lệ để xóa');
    if (mode === 'soft') {
      await Promise.all(codes.map(code => {
        const row = items.find(r => r.code === code)!;
        return masterService.updateAccount(code, {
          name: row.name,
          parentCode: row.parentCode,
          isDetail: row.isDetail,
          isActive: false,
          note: row.note,
        });
      }));
      dispatchAppToast(dispatch, { message: `Đã ngưng ${codes.length} tài khoản`, type: 'success' });
    } else {
      await Promise.all(codes.map(code => masterService.deleteAccount(code)));
      dispatchAppToast(dispatch, { message: `Đã xóa ${codes.length} tài khoản`, type: 'success' });
    }
    clearAccountSearchCache();
    refresh();
  };

  const indentLevel = (row: AccountGridRow) => Math.max(0, (row.level ?? 1) - 1);

  const rowMenuHintMessage = viewMobile
    ? CATALOG_LIST_ROW_MENU_HINT_TOUCH
    : CATALOG_LIST_ROW_MENU_HINT_DESKTOP;

  const handleRowOpenActionMenu = useCallback(
    ({ row, x, y }: { row: AccountGridRow; x: number; y: number }) => {
      selection.selectActiveRow(row);
      setRowMenu({ x, y, row });
    },
    [selection],
  );

  const handleRowMenuSelect = useCallback(
    (action: CatalogRowMenuAction) => {
      const row = rowMenu?.row;
      if (!row) return;
      switch (action) {
        case 'view':
          openView(row);
          break;
        case 'edit':
          openEdit(row);
          break;
        case 'history':
          toolbarBridgeRef.current?.openHistory();
          break;
        case 'renameCode':
          toolbarBridgeRef.current?.openRename();
          break;
        case 'delete': {
          if (!selection.isRowChecked(row)) {
            selection.toggleRow(row, true);
          }
          toolbarBridgeRef.current?.openDelete();
          break;
        }
        default:
          break;
      }
    },
    [rowMenu?.row, openEdit, openView, selection],
  );

  const rowMenuRow = rowMenu?.row;
  const rowMenuReadOnly = rowMenuRow ? isSharedCatalogReadOnly(rowMenuRow) : false;
  const rowMenuShowEdit = !!rowMenuRow && canWrite && !rowMenuReadOnly;
  const rowMenuShowView = !!rowMenuRow && (!canWrite || rowMenuReadOnly);

  const modalTitle = useMemo(() => {
    if (!editing) return 'Thêm tài khoản';
    if (formViewOnly) {
      return isSharedCatalogReadOnly(editing) ? 'Xem tài khoản dùng chung' : 'Xem tài khoản';
    }
    return 'Sửa tài khoản';
  }, [editing, formViewOnly]);

  return (
    <CatalogCodeReplaceProvider catalogKind={CATALOG_KIND}>
    <div className={`${styles.page} ${styles.catalogListPage}`} data-catalog-list-page>
      <CatalogPageHeader
        title="Danh mục tài khoản"
        titleIconClass="fas fa-book"
        hint={(
          <>
            {chartMeta?.hintText
              ? chartMeta.hintText
              : 'Chứng từ và phát sinh luôn riêng từng đơn vị. Danh mục TK có thể dùng chung sau khi được duyệt — sửa shared qua đề xuất + approve.'}
          </>
        )}
        hintTooltip={chartMeta?.hintText ?? 'Chứng từ và phát sinh luôn riêng từng đơn vị. Danh mục TK có thể dùng chung sau khi được duyệt — sửa shared qua đề xuất + approve.'}
      />

      <CatalogListMasterToolbarSection
        testIdPrefix={TEST_ID}
        catalogKind={CATALOG_KIND}
        shared={shared}
        selection={selection}
        totalCount={totalCount}
        selectableOnPage={gridRows.filter(r => !r.isReadOnly)}
        onAdd={openAdd}
        onEdit={openEdit}
        onRefresh={refresh}
        onBatchDelete={handleBatchDelete}
        showSchemaConfig
        onOpenSchemaConfig={() => setSchemaEditorOpen(true)}
        toolbarBridgeRef={toolbarBridgeRef}
      />

      <CatalogListShell
        testIdPrefix={TEST_ID}
        title="Danh sách tài khoản"
        showTableLoading={showTableLoading}
        footer={
          <CatalogListMasterListFooter
            testIdPrefix={TEST_ID}
            catalogKind={CATALOG_KIND}
            shared={shared}
            page={page}
            totalCount={totalCount}
            pageSize={pageSize}
            onPageChange={p => { setPage(p); selection.clearSelection(); }}
            onPageSizeChange={setPageSize}
          />
        }
        filters={(
          <CatalogListHeaderFilters testIdPrefix={TEST_ID}>
            <div className={styles.field} data-testid={`${TEST_ID}-field-search`}>
              <SearchTextInput
                label="Tìm kiếm"
                placeholder="Tìm mã, tên, TK cha..."
                value={searchDraft}
                onChange={setSearchDraft}
                onSearch={handleSearch}
                testId={`${TEST_ID}-search-text`}
              />
            </div>
            <div className={styles.field} data-testid={`${TEST_ID}-field-scope`}>
              <Select
                label="Phạm vi"
                value={scopeFilterOption}
                placeholder="Tất cả"
                className={selectPlaceholderClass(scopeFilterOption)}
                onChange={e => handleScopeFilterChange(e.target.value)}
                options={scopeFilterOptions}
              />
            </div>
            <ListSearchRefreshButtons
              testIdPrefix={TEST_ID}
              onSearch={handleSearch}
              onRefresh={refresh}
              showSearch={false}
            />
          </CatalogListHeaderFilters>
        )}
      >
        {gridRows.length === 0 ? (
          <div className={styles.empty}><i className="fas fa-inbox" /><p>Không có dữ liệu</p></div>
        ) : (
          <CatalogListGrid
            testIdPrefix={TEST_ID}
            rows={gridRows}
            page={page}
            pageSize={pageSize}
            selection={selection}
            getRowId={r => r.id}
            isRowSelectable={r => !r.isReadOnly}
            getRowEditBlockedMessage={getSharedCatalogEditBlockedMessage}
            rowEditHintDismissStorageKey={catalogRowEditHintDismissStorageKey(TEST_ID)}
            onRowOpenActionMenu={handleRowOpenActionMenu}
            rowMenuHintMessage={rowMenuHintMessage}
            rowMenuHintDismissStorageKey={catalogListRowMenuHintDismissStorageKey(TEST_ID)}
            enableRowMenuLongPress={viewMobile}
            tableConfig={tableConfig}
            headerCells={(
              <>
                <th>Mã</th>
                <th>Tên</th>
                <th>Phạm vi</th>
                <CatalogCompanyTh />
                <th>TK cha</th>
                <th>Chi tiết</th>
                <th>Trạng thái</th>
              </>
            )}
            renderRow={r => (
              <>
                <td>
                  <code style={{ paddingLeft: `${indentLevel(r) * 16}px` }}>{r.code}</code>
                </td>
                <td>{r.name}</td>
                <td>
                  <span className={r.scope === 'Shared' || r.scope === 'System' ? styles.tagSuccess : styles.tagDefault}>
                    {r.scope === 'Shared' || r.scope === 'System' ? 'Dùng chung' : 'Đơn vị'}
                  </span>
                </td>
                <CatalogCompanyTd label={r.companyName} />
                <td>{r.parentCode ?? '—'}</td>
                <td>{r.isDetail ? 'Có' : 'Không'}</td>
                <td>
                  <span className={r.isActive ? styles.tagSuccess : styles.tagDefault}>
                    {r.isActive ? 'Dùng' : 'Ngưng'}
                  </span>
                </td>
              </>
            )}
          />
        )}
      </CatalogListShell>

      <Modal
        isOpen={modalOpen}
        onClose={closeFormModal}
        title={modalTitle}
      >
        <div className={styles.modalBody} data-testid={`${TEST_ID}-form`}>
          <div className={styles.formGrid}>
            <div className={styles.masterCodeNameRow}>
              <div className={styles.field} data-testid={`${TEST_ID}-field-code`}>
                <label className={styles.label}>Mã tài khoản *</label>
                <Input
                  value={form.code ?? ''}
                  disabled={!!editing || formViewOnly}
                  error={errors.code}
                  className={styles.codeInput}
                  onChange={e => {
                    markDirty();
                    clearFieldError('code');
                    setForm(f => ({ ...f, code: normalizeCode(e.target.value) }));
                  }}
                />
              </div>
              <div className={styles.field} data-testid={`${TEST_ID}-field-name`}>
                <label className={styles.label}>Tên tài khoản *</label>
                <Input
                  value={form.name ?? ''}
                  disabled={formViewOnly}
                  error={errors.name}
                  onChange={e => {
                    markDirty();
                    clearFieldError('name');
                    setForm(f => ({ ...f, name: e.target.value }));
                  }}
                />
              </div>
            </div>
            <div className={styles.field} data-testid={`${TEST_ID}-field-parentCode`}>
              <label className={styles.label}>TK cha</label>
              <SearchInput
                config={parentAccountSearchConfig}
                value={form.parentCode ?? ''}
                primaryDisplay={formatAccountDisplay(form.parentCode ?? '', parentAccountName)}
                disabled={formViewOnly}
                onChange={a => {
                  if (editing?.code && a.code === editing.code) {
                    dispatchAppToast(dispatch, {
                      message: 'Không thể chọn chính tài khoản làm TK cha',
                      type: 'error',
                    });
                    return;
                  }
                  markDirty();
                  setForm(f => ({ ...f, parentCode: normalizeCode(a.code) }));
                  setParentAccountName(a.name);
                }}
                onClear={() => {
                  markDirty();
                  setForm(f => ({ ...f, parentCode: undefined }));
                  setParentAccountName('');
                }}
                showLabel={false}
                showSecondaryInput={false}
                placeholder="Mã hoặc tên TK..."
              />
            </div>
            <div className={styles.field} data-testid={`${TEST_ID}-field-isDetail`}>
              <Checkbox
                label="Tài khoản chi tiết"
                checked={form.isDetail ?? false}
                disabled={formViewOnly}
                onChange={e => {
                  markDirty();
                  setForm(f => ({ ...f, isDetail: e.target.checked }));
                }}
              />
            </div>
          </div>
          {(!formViewOnly || (editing && isSharedCatalogReadOnly(editing))) ? (
            <SharedCatalogFormActions
              testIdPrefix={TEST_ID}
              catalogKind={CATALOG_KIND}
              usageActive={chartMeta?.sharedUsageStatus === 'Active'}
              canRequest={!!chartMeta?.canRequestShared}
              row={editing}
              currentValues={{
                name: form.name,
                isDetail: form.isDetail,
                isActive: form.isActive,
              }}
              onSubmitUsage={shared.handleRequestUsage}
              onSubmitChange={handleSubmitProposalChange}
            />
          ) : null}
          {formViewOnly ? (
            <div className={styles.modalActions}>
              <Button variant="secondary" onClick={closeFormModal}>Đóng</Button>
            </div>
          ) : (
            <CatalogFormFooter
              companyName={editing?.companyName ?? sessionCompanyName}
              testIdPrefix={TEST_ID}
              checked={form.isActive ?? true}
              onActiveChange={c => {
                markDirty();
                setForm(f => ({ ...f, isActive: c }));
              }}
              onCancel={closeFormModal}
              onSave={handleSave}
              saving={saving}
              historySlot={
              <>
                <CatalogFormCodeReplaceSlot
                  testIdPrefix={TEST_ID}
                  catalogKind={CATALOG_KIND}
                  editing={editing ? { id: editing.id, code: editing.code } : null}
                  reloadKey={reloadKey}
                />
                <CatalogFormHistorySlot
                  testIdPrefix={TEST_ID}
                  catalogKind={CATALOG_KIND}
                  editing={editing ? { id: editing.id, code: editing.code } : null}
                />
              </>
              }
              saveDisabled={formViewOnly}
            />
          )}
        </div>
      </Modal>

      <CatalogRowActionMenu
        open={rowMenu != null}
        x={rowMenu?.x ?? 0}
        y={rowMenu?.y ?? 0}
        onClose={() => setRowMenu(null)}
        onSelect={handleRowMenuSelect}
        testIdPrefix={TEST_ID}
        showEdit={rowMenuShowEdit}
        showView={rowMenuShowView}
        showHistory={!!rowMenuRow}
        showRename={rowMenuShowEdit}
        showDelete={rowMenuShowEdit}
      />

      <LeaveConfirmModal {...leaveConfirmModalProps} />
      <CatalogUiSchemaEditorModal
        testIdPrefix={TEST_ID}
        catalogKind={CATALOG_KIND}
        isOpen={schemaEditorOpen}
        onClose={() => setSchemaEditorOpen(false)}
        onSaved={() => {
          reloadSchema();
          refresh();
        }}
      />
    </div>
    </CatalogCodeReplaceProvider>
  );
};

export default TaiKhoanPage;
